#include<bits/stdc++.h>
using namespace std;
long long n,k,Top,ans;
struct Leaf{long long h,c;};
bool operator<(Leaf lf1,Leaf lf2){
    if(lf1.c==lf2.c)
        return lf1.h>lf2.h;
    return lf1.c>lf2.c;
}
priority_queue<Leaf> q;
int main(){
    cin>>n>>k;
    for(long long i=1;i<=n;i++){
        Leaf lf;
        cin>>lf.c;
        lf.h=1;
        q.push(lf);
    }
    if((n-1)%(k-1)!=0)Top+=k-1-(n-1)%(k-1);//补齐权值为 0 的叶子节点
    for(long long i=1;i<=Top;i++){
        Leaf nd;
        nd.c=0,nd.h=1;
        q.push(nd);
    }
    Top+=n;
    while(Top!=1){
        Leaf lf;
        long long o=0,max_x=0;
        for(long long i=1;i<=k;i++){
            lf=q.top();
            o+=lf.c;
            max_x=max(max_x,lf.h);
            q.pop();
        }
        ans+=o;
        lf.c=o;
        lf.h=max_x+1;
        q.push(lf);
        Top-=k-1;
    }
    cout<<ans<<"\n"<<q.top().h-1;//这是顶，咱要的是叶，得 -1
    return 0;
}
